public static class GameSnapshotBuilder { public static SaveGameData Build(PlayerController player,BaseRoot baseRoot){ SaveGameData d=new(); if(player?.Stats!=null){d.PlayerHealth=player.Stats.CurrentHealth; d.PlayerMaxHealth=player.Stats.MaxHealth;} if(player?.Inventory!=null) foreach(InventorySlotState s in player.Inventory.Slots) if(s!=null&&!s.IsEmpty) d.InventoryItems.Add(new SaveSlotItemData{ItemId=s.ItemId,Amount=s.Amount,MaxStackSize=s.MaxStackSize,WeightPerUnit=s.WeightPerUnit}); if(baseRoot?.Storage!=null) foreach(StorageEntryState e in baseRoot.Storage.GetLogicState().Entries) if(e!=null&&!string.IsNullOrWhiteSpace(e.ItemId)&&e.Amount>0) d.StorageItems.Add(new SaveSlotItemData{ItemId=e.ItemId,Amount=e.Amount,MaxStackSize=e.MaxStackSize,WeightPerUnit=1f}); d.BaseLevel=baseRoot?.Progress?.BaseLevel??1; return d;} }